import os
import numpy as np

working_dir = os.path.join(os.getcwd(), "working")
experiment_data_path = os.path.join(working_dir, "experiment_data.npy")

experiment_data = np.load(experiment_data_path, allow_pickle=True).item()


def safe_float(x):
    try:
        return float(x)
    except Exception:
        return x


def format_value(x):
    if isinstance(x, (float, np.floating)):
        return f"{float(x):.6f}"
    if isinstance(x, (int, np.integer)):
        return str(int(x))
    return str(x)


def get_final_pair_value(seq):
    if seq is None or len(seq) == 0:
        return None
    item = seq[-1]
    if isinstance(item, (list, tuple, np.ndarray)) and len(item) >= 2:
        return safe_float(item[1])
    return safe_float(item)


def get_best_pair_value(seq, mode="max"):
    if seq is None or len(seq) == 0:
        return None
    values = []
    for item in seq:
        if isinstance(item, (list, tuple, np.ndarray)) and len(item) >= 2:
            values.append(safe_float(item[1]))
        else:
            values.append(safe_float(item))
    if len(values) == 0:
        return None
    return max(values) if mode == "max" else min(values)


def summarize_array(arr, prefix):
    arr = np.asarray(arr)
    if arr.size == 0:
        print(f"{prefix}: not available")
        return
    print(f"{prefix} mean: {format_value(arr.mean())}")
    print(f"{prefix} min: {format_value(arr.min())}")
    print(f"{prefix} max: {format_value(arr.max())}")


for dataset_name, dataset_data in experiment_data.items():
    print(f"Dataset: {dataset_name}")

    metrics = dataset_data.get("metrics", {})
    losses = dataset_data.get("losses", {})
    entropies = dataset_data.get("entropies", {})
    segment_accs = dataset_data.get("segment_accs", {})

    train_acc_final = get_final_pair_value(metrics.get("train", []))
    val_acc_final = get_final_pair_value(metrics.get("val", []))
    val_acc_best = get_best_pair_value(metrics.get("val", []), mode="max")

    train_loss_final = get_final_pair_value(losses.get("train", []))
    train_loss_best = get_best_pair_value(losses.get("train", []), mode="min")
    val_loss_final = get_final_pair_value(losses.get("val", []))
    val_loss_best = get_best_pair_value(losses.get("val", []), mode="min")

    if train_acc_final is not None:
        print(f"Final train accuracy: {format_value(train_acc_final)}")
    if val_acc_final is not None:
        print(f"Final validation accuracy: {format_value(val_acc_final)}")
    if val_acc_best is not None:
        print(f"Best validation accuracy: {format_value(val_acc_best)}")

    if train_loss_final is not None:
        print(f"Final train loss: {format_value(train_loss_final)}")
    if train_loss_best is not None:
        print(f"Best train loss: {format_value(train_loss_best)}")
    if val_loss_final is not None:
        print(f"Final validation loss: {format_value(val_loss_final)}")
    if val_loss_best is not None:
        print(f"Best validation loss: {format_value(val_loss_best)}")

    stream_metrics = metrics.get("stream", [])
    if len(stream_metrics) > 0:
        latest_stream = stream_metrics[-1]
        if isinstance(latest_stream, dict):
            if "no_adapt" in latest_stream:
                print(
                    f"Final stream shift-robust accuracy without adaptation: "
                    f"{format_value(latest_stream['no_adapt'])}"
                )
            if "always_on" in latest_stream:
                print(
                    f"Final stream shift-robust accuracy with always-on adaptation: "
                    f"{format_value(latest_stream['always_on'])}"
                )
            if "gated" in latest_stream:
                print(
                    f"Final stream shift-robust accuracy with confidence-gated adaptation: "
                    f"{format_value(latest_stream['gated'])}"
                )

    if isinstance(segment_accs, dict):
        for mode_name, values in segment_accs.items():
            values = np.asarray(values)
            if values.size > 0:
                label = {
                    "no_adapt": "Final mean segment accuracy without adaptation",
                    "always_on": "Final mean segment accuracy with always-on adaptation",
                    "gated": "Final mean segment accuracy with confidence-gated adaptation",
                }.get(mode_name, f"Final mean segment accuracy ({mode_name})")
                print(f"{label}: {format_value(values.mean())}")

    if isinstance(entropies, dict):
        for mode_name, values in entropies.items():
            values = np.asarray(values)
            if values.size > 0:
                label = {
                    "no_adapt": "Final mean predictive entropy without adaptation",
                    "always_on": "Final mean predictive entropy with always-on adaptation",
                    "gated": "Final mean predictive entropy with confidence-gated adaptation",
                }.get(mode_name, f"Final mean predictive entropy ({mode_name})")
                print(f"{label}: {format_value(values.mean())}")

    timestamps = dataset_data.get("timestamps", [])
    if len(timestamps) > 0:
        print(f"Final recorded timestamp: {format_value(safe_float(timestamps[-1]))}")

    print()

